/// 0000-MAIN-PROCESSING
fn p_0000_main_processing(state: &mut ProgramState) {
    p_1000_initialize(state);
    p_2000_export_customers(state);
    p_3000_export_accounts(state);
    p_4000_export_xrefs(state);
    p_5000_export_transactions(state);
    p_5500_export_cards(state);
    p_6000_finalize(state);
    { let _ = state._fh_customer_input.close();
        let _ = state._fh_account_input.close();
        let _ = state._fh_xref_input.close();
        let _ = state._fh_transaction_input.close();
        let _ = state._fh_card_input.close();
        let _ = state._fh_export_output.close();
        return; }
}

/// 1000-INITIALIZE
fn p_1000_initialize(state: &mut ProgramState) {
    println!("{}", "CBEXPORT: Starting Customer Data Export");
    p_1050_generate_timestamp(state);
    p_1100_open_files(state);
    println!("{}{}", "CBEXPORT: Export Date: ", state.ws_export_control.ws_export_date);
    println!("{}{}", "CBEXPORT: Export Time: ", state.ws_export_control.ws_export_time);
}

