/// 1100-OPEN-FILES
fn p_1100_open_files(state: &mut ProgramState) {
    customer_input_open_input(state);
    if !(state.ws_file_status_area.ws_customer_status == "00") {
        println!("{}{}", "ERROR: Cannot open CUSTOMER-INPUT, Status: ", state.ws_customer_status);
        p_9999_abend_program(state);
    }
    account_input_open_input(state);
    if !(state.ws_file_status_area.ws_account_status == "00") {
        println!("{}{}", "ERROR: Cannot open ACCOUNT-INPUT, Status: ", state.ws_account_status);
        p_9999_abend_program(state);
    }
    xref_input_open_input(state);
    if !(state.ws_file_status_area.ws_xref_status == "00") {
        println!("{}{}", "ERROR: Cannot open XREF-INPUT, Status: ", state.ws_xref_status);
        p_9999_abend_program(state);
    }
    transaction_input_open_input(state);
    if !(state.ws_file_status_area.ws_transaction_status == "00") {
        println!("{}{}", "ERROR: Cannot open TRANSACTION-INPUT, Status: ", state.ws_transaction_status);
        p_9999_abend_program(state);
    }
    card_input_open_input(state);
    if !(state.ws_file_status_area.ws_card_status == "00") {
        println!("{}{}", "ERROR: Cannot open CARD-INPUT, Status: ", state.ws_card_status);
        p_9999_abend_program(state);
    }
    export_output_open_output(state);
    if !(state.ws_file_status_area.ws_export_status == "00") {
        println!("{}{}", "ERROR: Cannot open EXPORT-OUTPUT, Status: ", state.ws_export_status);
        p_9999_abend_program(state);
    }
}

/// 2000-EXPORT-CUSTOMERS
fn p_2000_export_customers(state: &mut ProgramState) {
    println!("{}", "CBEXPORT: Processing customer records");
    p_2100_read_customer_record(state);
    while !(state.ws_file_status_area.ws_customer_status == "10") {
        // SKIP: unresolved ref
    }
    println!("{}{}", "CBEXPORT: Customers exported: ", state.ws_export_statistics.ws_customer_records_exported);
}

/// 2100-READ-CUSTOMER-RECORD
fn p_2100_read_customer_record(state: &mut ProgramState) {
    customer_input_read(state);
    if (!(state.ws_file_status_area.ws_customer_status == "00")) && (!(state.ws_file_status_area.ws_customer_status == "10")) {
        println!("{}{}", "ERROR: Reading CUSTOMER-INPUT, Status: ", state.ws_customer_status);
        p_9999_abend_program(state);
    }
}

